from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from flask_jwt_extended import JWTManager, jwt_required, get_jwt_identity

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///users.db'
app.config['JWT_SECRET_KEY'] = 'your_jwt_secret_key'
db = SQLAlchemy(app)
jwt = JWTManager(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(80), unique=True, nullable=False)
    email = db.Column(db.String(120), unique=True, nullable=False)
    account_type = db.Column(db.String(50), nullable=False)
    credits = db.Column(db.Integer, default=0)
    referral_code = db.Column(db.String(50), nullable=True)
    verified_status = db.Column(db.Boolean, default=False)

@app.route('/api/update_profile', methods=['PATCH'])
@jwt_required()
def update_profile():
    current_user_id = get_jwt_identity()
    user = User.query.get(current_user_id)

    if not user:
        return jsonify({"msg": "User not found"}), 404

    data = request.json

    if 'email' in data:
        user.email = data['email']
    if 'username' in data:
        user.username = data['username']
    if 'account_type' in data:
        user.account_type = data['account_type']
    if 'credits' in data:
        user.credits = data['credits']
    if 'referral_code' in data:
        user.referral_code = data['referral_code']
    if 'verified_status' in data:
        user.verified_status = data['verified_status']

    db.session.commit()
    return jsonify({"msg": "Profile updated successfully"}), 200

